#include<bits/stdc++.h>
using namespace std;
bool f(string s){
	for(int i=0;i<s.size()/2;i++){
		if(s[i]!=s[s.size()-1-i])return false;
	}return true;
}
int main(void){
    string s,str;int ans=0,x=1;
    cin>>s;
    for(int i=0;i<s.size();){
    	str="";
    	for(int j=0;(j<x)&&(i<s.size());i++,j++){
    		str+=s[i]; 
		}x++;
		ans+=f(str);
	}cout<<ans;
    return false;
}
